/*
 * Reinforcement Learning Components Simulation
 * Demonstrates: Agent, Environment, State, Action, Reward, Policy, Value Function, Model
 * Using a simple maze navigation task
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <stdbool.h>

// ============================================
// CONSTANTS AND CONFIGURATION
// ============================================
#define GRID_SIZE 4
#define NUM_ACTIONS 4
#define MAX_EPISODES 50
#define MAX_STEPS 100
#define LEARNING_RATE 0.1
#define DISCOUNT_FACTOR 0.9
#define EPSILON 0.1

// Action definitions
typedef enum {ACTION_UP, ACTION_DOWN, ACTION_LEFT, ACTION_RIGHT} Action;
const char* action_names[] = {"UP", "DOWN", "LEFT", "RIGHT"};

// ============================================
// COMPONENT 2: ENVIRONMENT
// ============================================
typedef struct {
 int row, col;
 int start_row, start_col;
 int goal_row, goal_col;
 int obstacle_row, obstacle_col;
} Environment;

// State representation (position in grid)
typedef struct {
 int row, col;
} State;

void env_init(Environment *env) {
 env->row = 0;
 env->col = 0;
 env->start_row = 0;
 env->start_col = 0;
 env->goal_row = 3;
 env->goal_col = 3;
 env->obstacle_row = 1;
 env->obstacle_col = 1;
}

State env_reset(Environment *env) {
 env->row = env->start_row;
 env->col = env->start_col;
 State s = {env->row, env->col};
 return s;
}

// Execute action and return next state and reward
// COMPONENT 5: REWARD - immediate feedback signal
void env_step(Environment *env, Action action, State *next_state, int *reward, bool *done) {
 // Calculate next position based on action
 int new_row = env->row;
 int new_col = env->col;

 switch(action) {
 case ACTION_UP: new_row = (env->row > 0) ? env->row - 1 : env->row; break;
 case ACTION_DOWN: new_row = (env->row < GRID_SIZE-1) ? env->row + 1 : env->row; break;
 case ACTION_LEFT: new_col = (env->col > 0) ? env->col - 1 : env->col; break;
 case ACTION_RIGHT: new_col = (env->col < GRID_SIZE-1) ? env->col + 1 : env->col; break;
 }

 // Update environment
 env->row = new_row;
 env->col = new_col;

 next_state->row = new_row;
 next_state->col = new_col;

 // Calculate reward based on new state
 if (new_row == env->goal_row && new_col == env->goal_col) {
 *reward = 10; // Positive reward for goal
 *done = true;
 } else if (new_row == env->obstacle_row && new_col == env->obstacle_col) {
 *reward = -5; // Negative reward for obstacle
 *done = false;
 } else {
 *reward = -1; // Step cost
 *done = false;
 }
}

// ============================================
// COMPONENTS 1, 6, 7, 8: AGENT with POLICY, VALUE FUNCTION, MODEL
// ============================================
typedef struct {
 // COMPONENT 7: VALUE FUNCTION - V(s) table
 double value_table[GRID_SIZE][GRID_SIZE];

 // COMPONENT 8: MODEL - transition model
 // model[action][state_index] = {next_state, reward}
 struct {
 State next_state;
 int reward;
 bool known;
 } model[NUM_ACTIONS][GRID_SIZE * GRID_SIZE];
} RLAgent;

int state_to_index(State s) {
 return s.row * GRID_SIZE + s.col;
}

void agent_init(RLAgent *agent) {
 // Initialize value table to zeros
 for (int i = 0; i < GRID_SIZE; i++) {
 for (int j = 0; j < GRID_SIZE; j++) {
 agent->value_table[i][j] = 0.0;
 }
 }

 // Initialize model as unknown
 for (int a = 0; a < NUM_ACTIONS; a++) {
 for (int s = 0; s < GRID_SIZE * GRID_SIZE; s++) {
 agent->model[a][s].known = false;
 }
 }
}

// COMPONENT 6: POLICY - Epsilon-greedy action selection
Action agent_select_action(RLAgent *agent, State state) {
 if ((double)rand() / RAND_MAX < EPSILON) {
 // Exploration: random action
 return rand() % NUM_ACTIONS;
 } else {
 // Exploitation: best action based on value function
 double best_value = -99999;
 Action best_action = ACTION_UP;

 for (int a = 0; a < NUM_ACTIONS; a++) {
 int idx = state_to_index(state);
 // If model knows this transition, use model prediction
 double action_value = 0;
 if (agent->model[a][idx].known) {
 State next = agent->model[a][idx].next_state;
 int r = agent->model[a][idx].reward;
 action_value = r + DISCOUNT_FACTOR * agent->value_table[next.row][next.col];
 }

 if (action_value > best_value) {
 best_value = action_value;
 best_action = a;
 }
 }
 return best_action;
 }
}

// COMPONENT 7: VALUE FUNCTION UPDATE - Temporal Difference learning
void agent_update_value(RLAgent *agent, State state, int reward, State next_state) {
 double current_value = agent->value_table[state.row][state.col];
 double next_value = agent->value_table[next_state.row][next_state.col];

 // TD Update: V(s) = V(s) + alpha * [r + gamma * V(s') - V(s)]
 double td_error = reward + DISCOUNT_FACTOR * next_value - current_value;
 agent->value_table[state.row][state.col] += LEARNING_RATE * td_error;
}

// COMPONENT 8: MODEL UPDATE - Learn transition dynamics
void agent_update_model(RLAgent *agent, State state, Action action, 
 State next_state, int reward) {
 int s_idx = state_to_index(state);
 agent->model[action][s_idx].next_state = next_state;
 agent->model[action][s_idx].reward = reward;
 agent->model[action][s_idx].known = true;
}

// Main learning step
void agent_learn(RLAgent *agent, State state, Action action, 
 int reward, State next_state) {
 // Update value function (model-free)
 agent_update_value(agent, state, reward, next_state);

 // Update model (for model-based planning)
 agent_update_model(agent, state, action, next_state, reward);
}

// ============================================
// MAIN: DEMONSTRATE RL INTERACTION LOOP
// ============================================
int main() {
 srand(time(NULL));

 printf("========================================================\n");
 printf("REINFORCEMENT LEARNING COMPONENTS DEMONSTRATION (C)\n");
 printf("========================================================\n");
 printf("Components: Agent, Environment, State, Action, Reward,\n");
 printf(" Policy (ε-greedy), Value Function (V), Model\n");
 printf("========================================================\n\n");

 // Initialize components
 Environment env;
 RLAgent agent;

 env_init(&env);
 agent_init(&agent);

 // Run multiple episodes
 for (int episode = 0; episode < 3; episode++) {
 printf("\n=== EPISODE %d ===\n", episode + 1);

 // Reset environment - get initial state
 State state = env_reset(&env);
 int total_reward = 0;

 for (int step = 0; step < MAX_STEPS; step++) {
 // Step 1: AGENT observes STATE
 printf("Step %d: State=(%d,%d) ", step + 1, state.row, state.col);

 // Step 2: AGENT selects ACTION based on POLICY
 Action action = agent_select_action(&agent, state);
 printf("Action=%s ", action_names[action]);

 // Step 3: ACTION affects ENVIRONMENT
 State next_state;
 int reward;
 bool done;
 env_step(&env, action, &next_state, &reward, &done);

 // Step 4: AGENT receives REWARD
 printf("Reward=%d ", reward);
 total_reward += reward;

 // Step 5: AGENT LEARNS (update value function and model)
 agent_learn(&agent, state, action, reward, next_state);

 printf("V(%d,%d)=%.2f\n", state.row, state.col, 
 agent.value_table[state.row][state.col]);

 // Move to next state
 state = next_state;

 if (done) {
 printf("*** GOAL REACHED! ***\n");
 break;
 }
 }

 printf("Total Reward: %d\n", total_reward);
 }

 // Display learned value function
 printf("\n========================================================\n");
 printf("LEARNED VALUE FUNCTION (State-Value Table)\n");
 printf("========================================================\n");

 for (int i = 0; i < GRID_SIZE; i++) {
 printf("|");
 for (int j = 0; j < GRID_SIZE; j++) {
 printf(" %6.2f |", agent.value_table[i][j]);
 }
 printf("\n");
 }

 return 0;
}
